import{_ as t,o as e,c as s,ae as r}from"./chunks/framework.BzQXgbNp.js";const a="/assets/shop-gui.A9N3807H.png",l="/assets/shop-detail.mQOGXFZF.png",m=JSON.parse('{"title":"🏪 Minecraft 箱子商店系統概覽","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Shop-System.md","filePath":"Mc-Shop-System.md"}'),c={name:"Mc-Shop-System.md"};function i(n,o,d,p,g,h){return e(),s("div",null,[...o[0]||(o[0]=[r('<h1 id="🏪-minecraft-箱子商店系統概覽" tabindex="-1">🏪 Minecraft 箱子商店系統概覽 <a class="header-anchor" href="#🏪-minecraft-箱子商店系統概覽" aria-label="Permalink to &quot;🏪 Minecraft 箱子商店系統概覽&quot;">​</a></h1><p>箱子商店是本伺服器的核心交易系統，讓所有玩家都能在自己領地內輕鬆擺攤賣貨或收購材料。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>推薦您在遊戲中優先輸入 <strong><code>/shop</code></strong> 指令開啟箱子選單。在此選單中，您可以直觀地瀏覽所有玩家正在販售的商品，並滑鼠點選快速傳送，比起手動跑圖更方便快捷！</p></div><p><img src="'+a+'" alt="遊戲內 /shop 箱子選單"></p><hr><h2 id="🪙-1-買家交易操作" tabindex="-1">🪙 1. 買家交易操作 <a class="header-anchor" href="#🪙-1-買家交易操作" aria-label="Permalink to &quot;🪙 1. 買家交易操作&quot;">​</a></h2><p><img src="'+l+'" alt="商店詳細資訊"></p><p>當您傳送到其他玩家的商店前時，可以按照以下方式進行交易：</p><ul><li><strong>觸發交易面板</strong>： <ul><li><strong>【右鍵點擊】 商店告示牌</strong>，或</li><li><strong>【左鍵擊打】 商店箱子（或木桶）</strong></li></ul></li><li><strong>進行交易（聊天欄互動）</strong>： <ul><li>點擊上述方塊後，聊天欄會顯示該商店的販售狀態、庫存與交易選項： <ul><li><code>[購買商品]</code>：點選後，在聊天欄輸入您想購買的數量（或輸入 <code>all</code> / <code>全部</code> 一次買滿，輸入 <code>取消</code> 退出）。</li><li><code>[出售商品]</code>：若商店有啟用收購模式，點選後在聊天欄輸入您想賣給店主的數量（或輸入 <code>all</code> / <code>全部</code> 一次賣光）。</li></ul></li></ul></li><li><strong>安全防盜鎖定</strong>： <ul><li>當您不是店主時，對著商店的 <strong>【箱子按右鍵】</strong> 會被系統防盜功能攔截並播放鎖定聲效，提示 <code>§c[Craft-Core] 您不能開啟此箱子商店！</code>，保護店主的庫存不被竊取。</li></ul></li></ul><hr><h2 id="📈-2-商店升級與管理" tabindex="-1">📈 2. 商店升級與管理 <a class="header-anchor" href="#📈-2-商店升級與管理" aria-label="Permalink to &quot;📈 2. 商店升級與管理&quot;">​</a></h2><ul><li><strong>商店升級 <code>/shop upgrade</code></strong>：每位玩家預設最多可建立 15 個商店。在遊戲內輸入此指令，消耗 <strong>$5,000 金幣</strong> 即可永久增加 1 個商店建立上限。</li><li><strong>商店更名 <code>/shop rename &lt;座標&gt; &lt;自訂名稱&gt;</code></strong>：花費 <strong>$5,000 金幣</strong> 將指定座標的商店更名，名稱會同步顯示在告示牌與網頁瀏覽器上。</li></ul>',12)])])}const _=t(c,[["render",i]]);export{m as __pageData,_ as default};
